ValidationRule.errorConditionFormula:
OR(
    AND(
        OR(NOT(ISBLANK(APHA_TestDay2Avian__c)), NOT(ISBLANK(APHA_TestDay2Bovine__c))),
        NOT(ISBLANK(APHA_TestDay2DIVA__c))
    ),
    AND(
        ISBLANK(APHA_TestDay2DIVA__c),
        OR(
            AND(NOT(ISBLANK(APHA_TestDay2Avian__c)), ISBLANK(APHA_TestDay2Bovine__c)),
            AND(ISBLANK(APHA_TestDay2Avian__c), NOT(ISBLANK(APHA_TestDay2Bovine__c)))
        )
    )
)
